import React, { useEffect, useCallback, useRef, useState } from 'react';
import { View, Text, StyleSheet, SafeAreaView, ScrollView, StatusBar, Pressable, Vibration } from 'react-native';
import { PetSprite, PetStatus, PetActions } from '../components/Pet';
import { usePetStore } from '../stores/petStore';
import { COLORS, SPACING, FONT_SIZES } from '../constants/theme';
import { SettingsScreen } from './SettingsScreen';

export const HomeScreen: React.FC = () => {
  const pet = usePetStore();
  const intervalRef = useRef<NodeJS.Timeout | null>(null);
  const [showSettings, setShowSettings] = useState(false);

  useEffect(() => {
    pet.loadPet();
  }, []);

  useEffect(() => {
    intervalRef.current = setInterval(() => {
      pet.tick();
    }, 60000);

    return () => {
      if (intervalRef.current) clearInterval(intervalRef.current);
    };
  }, []);

  const playFeedback = useCallback(() => {
    Vibration.vibrate(50);
  }, []);

  const handleFeed = useCallback(() => { pet.feed(); playFeedback(); }, [pet]);
  const handleWater = useCallback(() => { pet.water(); playFeedback(); }, [pet]);
  const handleBathe = useCallback(() => { pet.bathe(); playFeedback(); }, [pet]);
  const handlePet = useCallback(() => { pet.pet(); playFeedback(); }, [pet]);

  if (showSettings) {
    return <SettingsScreen />;
  }

  return (
    <SafeAreaView style={styles.container}>
      <StatusBar barStyle="dark-content" backgroundColor={COLORS.background} />
      <ScrollView contentContainerStyle={styles.scrollContent}>
        <View style={styles.header}>
          <Text style={styles.title}>PetPal 🐣</Text>
          <Pressable onPress={() => setShowSettings(true)} style={styles.settingsButton}>
            <Text style={styles.settingsText}>⚙️</Text>
          </Pressable>
        </View>

        <View style={styles.petArea}>
          <PetSprite onInteract={handlePet} />
        </View>

        <PetStatus />

        <PetActions onFeed={handleFeed} onWater={handleWater} onBathe={handleBathe} onPet={handlePet} />

        <View style={styles.tips}>
          <Text style={styles.tipsTitle}>小提示</Text>
          <Text style={styles.tipsText}>
            • 按时喂食和喝水，保持饱食度和水分值{"\n"}
            • 经常抚摸可以增加亲密度{"\n"}
            • 卫生值低时要记得洗澡哦{"\n"}
            • 照顾好宠物，它会进化成更可爱的形态！
          </Text>
        </View>
      </ScrollView>
    </SafeAreaView>
  );
};

const styles = StyleSheet.create({
  container: { flex: 1, backgroundColor: COLORS.background },
  scrollContent: { flexGrow: 1, paddingBottom: SPACING.xl },
  header: { flexDirection: 'row', justifyContent: 'space-between', alignItems: 'center', paddingHorizontal: SPACING.lg, paddingVertical: SPACING.md },
  title: { fontSize: FONT_SIZES.xxl, fontWeight: 'bold', color: COLORS.primaryDark },
  settingsButton: { padding: SPACING.sm },
  settingsText: { fontSize: 24 },
  petArea: { alignItems: 'center', justifyContent: 'center', paddingVertical: SPACING.lg },
  tips: { margin: SPACING.md, padding: SPACING.md, backgroundColor: COLORS.primaryLight, borderRadius: 12 },
  tipsTitle: { fontSize: FONT_SIZES.md, fontWeight: '600', color: COLORS.text, marginBottom: SPACING.sm },
  tipsText: { fontSize: FONT_SIZES.sm, color: COLORS.text, lineHeight: 22 },
});
